mapper.select:
SELECT lr.*, cr.relic_name AS relicName, su.real_name AS borrowerName FROM loan_record lr LEFT JOIN cultural_relic cr ON lr.relic_id = cr.id LEFT JOIN sys_user su ON lr.borrower_id = su.id
AND lr.status = #{status}
ORDER BY lr.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM loan_record
WHERE YEAR(loan_date) = #{year}
AND MONTH(loan_date) = #{month}

SELECT COUNT(1)
FROM loan_record
WHERE DATE(loan_date) BETWEEN #{startDate} AND #{endDate}

mapper.update:
UPDATE loan_record
relic_id = #{relicId}, borrower_id = #{borrowerId}, borrower_unit = #{borrowerUnit}, borrower_phone = #{borrowerPhone}, loan_date = #{loanDate}, expected_return_date = #{expectedReturnDate}, actual_return_date = #{actualReturnDate}, purpose = #{purpose}, status = #{status}, approver_name = #{approverName}, approve_time = #{approveTime}, approve_remark = #{approveRemark}, update_time = #{updateTime},
WHERE id = #{id}

